describe('OpenAPI Helpers', () => {
  describe('getEndpointsFromOpenApi', () => {
    test('should extract endpoints from OpenAPI spec', () => {
      const endpoints = getEndpointsFromOpenApi(mockOpenApiSpecMcpEnabled);

      expect(endpoints).toHaveLength(2);
      expect(endpoints[0]!.method).toBe('get');
      expect(endpoints[0]!.path).toBe('/pets');
      expect(endpoints[1]!.method).toBe('post');
      expect(endpoints[1]!.path).toBe('/pets');
    });

    test('should handle empty paths object', () => {
      const emptySpec = { ...mockOpenApiSpecMcpEnabled, paths: {} };
      const endpoints = getEndpointsFromOpenApi(emptySpec);
      expect(endpoints).toHaveLength(0);
    });
  });

  describe('convertEndpointToCategorizedZod', () => {
    test('should convert endpoint parameters to Zod schemas', () => {
      const endpoints = getEndpointsFromOpenApi(mockOpenApiSpecMcpEnabled);
      const getEndpoint = endpoints[0]!;

      const converted = convertEndpointToCategorizedZod('mock-env-key', getEndpoint);

      expect(converted.method).toBe('get');
      expect(converted.queries).toBeDefined();
      expect(converted.queries.limit).toBeInstanceOf(z.ZodType);
    });

    test('should handle endpoints with request bodies', () => {
      const endpoints = getEndpointsFromOpenApi(mockOpenApiSpecMcpEnabled);
      const postEndpoint = endpoints[1]!;

      const converted = convertEndpointToCategorizedZod('mock-env-key', postEndpoint);

      expect(converted.method).toBe('post');
      expect(converted.body).toBeDefined();
      expect(converted.body?.body).toBeInstanceOf(z.ZodType);
    });
  });

  describe('getMcpToolsFromOpenApiSpecs', () => {
    test('should return all paths on mcp enabled spec', () => {
      const tools = getMcpToolsAndEndpointsFromOpenApiSpec(mockOpenApiSpecMcpEnabled);
      expect(tools).toHaveLength(2);
      expect(tools[0]!.tool.name).toBe('get-pets');
      expect(tools[0]!.tool.description).toBe('Get all pets from the database');
      expect(tools[1]!.tool.name).toBe('/pets');
      expect(tools[1]!.tool.description).toBe('post /pets');
    });

    test('should return all paths on mcp enabled spec part two', () => {
      const tools = getMcpToolsAndEndpointsFromOpenApiSpec(mockOpenApiSpecMcpEnabledTwo);
      expect(tools).toHaveLength(2);
      expect(tools[0]!.tool.name).toBe('trigger-an-update');
      expect(tools[0]!.tool.description).toBe(
        'Trigger an update after updating your OpenAPI document by calling this endpoint in a CI check.'
      );
      expect(tools[1]!.tool.name).toBe('get-the-status-of-an-update');
      expect(tools[1]!.tool.description).toBe('get /project/update-status/{statusId}');
    });

    test('should return all paths on mcp path specific enabled spec', () => {
      const tools = getMcpToolsAndEndpointsFromOpenApiSpec(mockOpenApiSpecMcpPathSpecificEnabled);
      expect(tools).toHaveLength(1);
      expect(tools[0]!.tool.name).toBe('/pets');
      expect(tools[0]!.tool.description).toBe('get /pets');
    });

    test('should return no paths on mcp disabled spec', () => {
      const tools = getMcpToolsAndEndpointsFromOpenApiSpec(mockOpenApiSpecNoMcpSettings);
      expect(tools).toHaveLength(0);
    });
  });
});
